import Link from '@kyokuya/react-link'
import { MarkdownProvider } from '@kyokuya/react-markdown'
import { ArrowRightAltOutlined } from '@material-ui/icons'
import cn from 'clsx'
import { graphql } from 'gatsby'
import React, { useMemo } from 'react'
import Seo from '@/component/seo'
import Toc from '@/component/toc'
import type { TocItemData } from '@/component/toc'
import useActivatedIdentifier from '@/core/hook/useActivatedIdentifier'
import { resolveIdentifier } from '@/core/util/url'
import type { BlogPostListQuery } from '@/types/gatsby-graphql'
import BlogLayout from '../layout'
import type { PostItem } from '../layout/search-panel'
import PostContent from '../post/context'
import classes from '../style/index.module.styl'
import PostListPagination from './pagination'

export interface BlogPostListContext {
  /**
   * Current page number.
   */
  current: number
  /**
   * Count of total pages.
   */
  totalPage: number
  /**
   * Url prefix of post pagination page.
   */
  urlPrefix: string
  /**
   * Url of pagination pages.
   */
  paginationUrl: string
}

export interface BlogPostListLayoutProps {
  data: BlogPostListQuery
  pageContext: BlogPostListContext
}

export default function BlogPostListLayout(
  props: BlogPostListLayoutProps,
): React.ReactElement {
  const { current, totalPage, urlPrefix, paginationUrl } = props.pageContext

  const resolveUrl = useMemo<(pageNo: number) => string | null>(() => {
    const prefix = (urlPrefix + '/').replace(/[/]+/g, '/')
    return (pageNo: number): string | null => {
      if (pageNo <= 0 || pageNo > totalPage) return null
      return prefix + '' + pageNo
    }
  }, [urlPrefix, totalPage])

  const {
    activatedIdentifier,
    refreshActivatedIdentifier,
    pauseWatchingScroll,
  } = useActivatedIdentifier(classes.postCardItem, 0)

  const { postItems, tocNodes, articles, description } = (() => {
    const tocNodes: TocItemData[] = []
    const articles: React.ReactElement[] = []
    const posts = props.data.allMarkdownYozora.nodes ?? []
    const postItems = (props.data.postItems.nodes ?? []) as PostItem[]
    const descriptions: string[] = []

    for (const post of posts) {
      const {
        title,
        createAt,
        timeToRead,
        excerptAst,
        ecmaImports,
        definitionMap,
        footnoteDefinitionMap,
        tags,
      } = post
      const slug: string = post.fields!.slug ?? ''

      const tocItem: TocItemData = {
        depth: 1,
        identifier: 'post-' + resolveIdentifier(title ?? slug),
        title,
      }

      const article: React.ReactElement = (
        <MarkdownProvider
          key={tocItem.identifier}
          ecmaImports={ecmaImports}
          definitionMap={definitionMap}
          footnoteDefinitionMap={footnoteDefinitionMap}
        >
          <div id={tocItem.identifier} className={classes.postCardItem}>
            <PostContent
              title={title!}
              createAt={createAt!}
              timeToRead={timeToRead!}
              tags={tags! as any}
              ast={excerptAst}
              slug={slug}
              shouldRenderFooter={false}
            />
            <Link
              url={slug}
              title={title!}
              itemProp="url"
              className={classes.postReadMore}
            >
              <span itemProp="headline" aria-label={title!}>
                阅读全文
              </span>
              <ArrowRightAltOutlined />
            </Link>
          </div>
        </MarkdownProvider>
      )

      if (title != null) descriptions.push(title)
      tocNodes.push(tocItem)
      articles.push(article)
    }
    return {
      postItems,
      tocNodes,
      articles,
      description: descriptions.join('\n\n'),
    }
  })()

  return (
    <BlogLayout
      onScroll={refreshActivatedIdentifier}
      paginationUrl={paginationUrl}
      postItems={postItems}
      head={<Seo title={'博文列表-' + current} description={description} />}
      content={
        <div className={classes.postList}>
          {articles}
          <div
            className={cn(
              classes.paginationContainer,
              classes.frostedGlassPanel,
            )}
          >
            <PostListPagination
              totalPage={totalPage}
              current={current}
              resolveUrl={resolveUrl}
            />
          </div>
        </div>
      }
      nav={
        <Toc
          activatedIdentifier={activatedIdentifier}
          nodes={tocNodes}
          pauseWatchingScroll={pauseWatchingScroll}
        />
      }
    />
  )
}

export const query = void graphql`
query BlogPostList(
  $contentType: String!
  $skip: Int!,
  $limit: Int!
) {
  allMarkdownYozora(
    filter: { fields: { contentType: { eq: $contentType } } }
    sort: { fields: [createAtISO], order: DESC }
    limit: $limit
    skip: $skip
  ) {
    nodes {
      title
      description
      createAt(formatString: "YYYY-MM-DD")
      updateAt(formatString: "YYYY-MM-DD")
      timeToRead(formatString: "m[min] s[s]")
      categories
      tags
      ecmaImports
      definitionMap
      footnoteDefinitionMap
      excerptAst(pruneLength: 512)
      fields {
        slug
      }
    }
  }
  postItems: allMarkdownYozora(
    filter: { fields: { contentType: { eq: $contentType } } }
  ) {
    nodes {
      title
      createAt(formatString: "YYYY-MM-DD")
      tags
      fields {
        slug
      }
    }
  }
}
`
